import numpy as np
from sklearn.metrics.pairwise import cosine_similarity

def search_similar(
    query_embedding: list[float],
    document_embeddings: list[list[float]],
    top_k: int = 10
) -> list[tuple[int, float]]:
    """Find most similar documents by cosine similarity."""
    query = np.array(query_embedding).reshape(1, -1)
    docs = np.array(document_embeddings)
    similarities = cosine_similarity(query, docs)[0]
    top_indices = np.argsort(similarities)[::-1][:top_k]
    return [(int(idx), float(similarities[idx])) for idx in top_indices]

def recall_at_k(search_fn, test_data: list[dict], k: int = 10) -> float:
    """
    test_data: list of {"query_emb": ..., "relevant_ids": [int, ...]}
    Returns average Recall@k.
    """
    recalls = []
    for item in test_data:
        results = search_fn(item["query_emb"], top_k=k)
        result_ids = set(idx for idx, _ in results)
        relevant = set(item["relevant_ids"])
        recalls.append(len(result_ids & relevant) / len(relevant))
    return float(np.mean(recalls))

def mean_reciprocal_rank(search_fn, test_data: list[dict], k: int = 10) -> float:
    """Returns average MRR@k."""
    mrrs = []
    for item in test_data:
        results = search_fn(item["query_emb"], top_k=k)
        for rank, (idx, _) in enumerate(results, 1):
            if idx in item["relevant_ids"]:
                mrrs.append(1 / rank)
                break
        else:
            mrrs.append(0)
    return float(np.mean(mrrs))
